type DefensePhaseProps = { difficulty: BattleDifficulty; homeTeamId: string; awayTeamId: string; awayTeamPlayers?: string[]; defenderName?: string; keeperName?: string; playerKit?: TeamKit; opponentKit?: TeamKit; onRoundEnd: (outcome: DefenseOutcome) => void; isPaused?: boolean; onAudioOverride?: (src: string | null) => void; showControls?: boolean; roundIntroComment?: string }
type EnemyType = 'normal' | 'sprinter' | 'tank' | 'dribbler' | 'feinter' | 'captain' | 'kamikaze'
